<?php declare(strict_types=1);session_start();require __DIR__.'/../includes/functions.php';interface Downloadable{public function download():string;}class Book{public function __construct(protected string $title,protected string $author,protected float $price){if($price<0)throw new InvalidArgumentException('Giá không được âm.');}public function data():array{return ['type'=>'Book','title'=>$this->title,'author'=>$this->author,'price'=>$this->price,'size'=>null];}}class Ebook extends Book implements Downloadable{public function __construct(string $title,string $author,float $price,private float $size){parent::__construct($title,$author,$price);if($size<=0)throw new InvalidArgumentException('Kích thước file phải lớn hơn 0.');}public function download():string{return "Đã tạo yêu cầu tải ebook '{$this->title}'.";}public function data():array{return ['type'=>'Ebook','title'=>$this->title,'author'=>$this->author,'price'=>$this->price,'size'=>$this->size];}}
$_SESSION['library']??=[];$message='';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$action=(string)($_POST['action']??'add');if($action==='reset'){$_SESSION['library']=[];header('Location:index.php');exit;}try{$type=(string)($_POST['type']??'book');$title=trim((string)($_POST['title']??''));$author=trim((string)($_POST['author']??''));$price=filter_input(INPUT_POST,'price',FILTER_VALIDATE_FLOAT);if($title===''||$author===''||$price===false||$price===null)throw new InvalidArgumentException('Thông tin sách chưa hợp lệ.');if($type==='ebook'){$size=filter_input(INPUT_POST,'size',FILTER_VALIDATE_FLOAT);if($size===false||$size===null)throw new InvalidArgumentException('Kích thước ebook không hợp lệ.');$item=new Ebook($title,$author,$price,$size);$message=$item->download();}else{$item=new Book($title,$author,$price);$message='Đã thêm sách in.';}$_SESSION['library'][]=$item->data();}catch(Throwable $e){$error=$e->getMessage();}}$pageTitle='Bài 07 - Library';$basePath='..';$current='bai07';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 07</div><h1>Quản lý thư viện</h1><p class="subtitle">Book, Ebook, kế thừa và interface Downloadable.</p><?php if($message):?><div class="alert ok"><?=e($message)?></div><?php endif;?><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><section class="card"><h2>Thêm tài liệu</h2><form method="post"><div class="form-grid"><div class="group"><label>Loại</label><select name="type"><option value="book">Sách in</option><option value="ebook" <?=($_POST['type']??'')==='ebook'?'selected':''?>>Ebook</option></select></div><div class="group"><label>Tên sách</label><input name="title" value="<?=old('title','Lập trình PHP căn bản')?>" required></div><div class="group"><label>Tác giả</label><input name="author" value="<?=old('author','Nguyễn Văn A')?>" required></div><div class="group"><label>Giá</label><input type="number" name="price" min="0" step="1000" value="<?=old('price','120000')?>" required></div><div class="group full"><label>Kích thước Ebook (MB)</label><input type="number" name="size" min="0.1" step="0.1" value="<?=old('size','5.5')?>"></div></div><div class="actions"><button class="btn primary" name="action" value="add">Thêm tài liệu</button><button class="btn danger" name="action" value="reset">Xóa danh sách</button></div></form></section><section class="card" style="margin-top:20px"><h2>Danh sách tài liệu</h2><?php if($_SESSION['library']):?><div class="table-wrap"><table><thead><tr><th>Loại</th><th>Tên</th><th>Tác giả</th><th>Giá</th><th>Kích thước</th></tr></thead><tbody><?php foreach($_SESSION['library'] as $it):?><tr><td><?=e($it['type'])?></td><td><?=e($it['title'])?></td><td><?=e($it['author'])?></td><td><?=e(money((float)$it['price']))?></td><td><?=$it['size']!==null?e((string)$it['size']).' MB':'—'?></td></tr><?php endforeach;?></tbody></table></div><?php else:?><p class="muted">Chưa có tài liệu.</p><?php endif;?></section><?php require __DIR__.'/../includes/footer.php';?>
